
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Bus, UserCog, User, ShieldCheck, LogIn } from "lucide-react";
import Link from 'next/link';
import { cn } from '@/lib/utils';

export default function LoginPage() {
  const router = useRouter();
  const { toast } = useToast();
  const [role, setRole] = useState('parent');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    // Simulate API call
    setTimeout(() => {
      if ((role === 'admin' && email === 'admin@yellowtransit.com') ||
          (role === 'driver' && email === 'driver@yellowtransit.com') ||
          (role === 'parent' && email === 'parent@yellowtransit.com')) {
        
        toast({
          title: "Login Successful",
          description: `Welcome! Redirecting to the ${role} dashboard.`,
        });
        
        // In a real app, you'd handle session/token here
        router.push(`/dashboard/${role}`);

      } else {
        toast({
          variant: 'destructive',
          title: "Login Failed",
          description: "Invalid email or password for the selected role.",
        });
        setIsLoading(false);
      }
    }, 1000);
  };
  
  const fillDemoCredentials = () => {
      const credentials = {
          parent: 'parent@yellowtransit.com',
          admin: 'admin@yellowtransit.com',
          driver: 'driver@yellowtransit.com'
      }
      setEmail(credentials[role as keyof typeof credentials]);
      setPassword('password');
  }

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-muted/40 p-4">
      <div className="absolute top-4 left-4 z-10 hidden md:flex">
        <Link href="/" className="flex items-center justify-center gap-2">
            <Bus className="h-6 w-6 text-primary" />
            <span className="text-lg font-semibold font-headline">Yellow Transit</span>
        </Link>
      </div>

      <Card className="w-full max-w-sm z-10">
        <CardHeader className="text-center">
            <div className="mx-auto bg-primary/20 text-primary p-3 rounded-full w-fit mb-4">
                <Bus className="h-8 w-8" />
            </div>
            <CardTitle className="text-2xl font-bold font-headline">Yellow Transit Login</CardTitle>
            <CardDescription>Select your role to sign in.</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-2">
                <Label>I am a:</Label>
                <div className="grid grid-cols-3 gap-2">
                    <Button type="button" variant={role === 'parent' ? 'default' : 'outline'} onClick={() => setRole('parent')}><User className="mr-2 h-4 w-4" />Parent</Button>
                    <Button type="button" variant={role === 'admin' ? 'default' : 'outline'} onClick={() => setRole('admin')}><UserCog className="mr-2 h-4 w-4" />Admin</Button>
                    <Button type="button" variant={role === 'driver' ? 'default' : 'outline'} onClick={() => setRole('driver')}><ShieldCheck className="mr-2 h-4 w-4" />Driver</Button>
                </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="email">Email</Label>
              <Input id="email" type="email" placeholder="m@example.com" required value={email} onChange={e => setEmail(e.target.value)} disabled={isLoading} />
            </div>
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <Label htmlFor="password">Password</Label>
                <Link
                    href="#"
                    className="text-sm font-medium text-primary hover:underline"
                >
                    Forgot password?
                </Link>
              </div>
              <Input id="password" type="password" required value={password} onChange={e => setPassword(e.target.value)} disabled={isLoading} />
            </div>
            <Button type="submit" className="w-full" disabled={isLoading}>
              <LogIn className="mr-2 h-4 w-4" />
              {isLoading ? 'Signing In...' : 'Sign In'}
            </Button>
          </form>
        </CardContent>
        <CardFooter className="flex-col gap-4">
            <div className="text-center">
                <p className="text-xs text-muted-foreground mb-2">Demo Mode:</p>
                <Button variant="link" className="text-xs h-auto p-0" onClick={fillDemoCredentials}>Fill Demo Credentials for {role.charAt(0).toUpperCase() + role.slice(1)}</Button>
            </div>
        </CardFooter>
      </Card>
       <div className="absolute bottom-4 text-center z-10">
          <p className="text-xs text-muted-foreground">
            © 2025 Yellow Transit. All rights reserved.
          </p>
        </div>
    </div>
  );
}
